import{_ as a,o as i,c as s,a2 as e}from"./chunks/framework.LN3EJxkW.js";const c=JSON.parse('{"title":"信息架构、用户流程、任务流程、状态与反馈","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/00-foundations/04-ia-user-flow-task-flow-state-feedback.md","filePath":"03-interaction-design/notes/00-foundations/04-ia-user-flow-task-flow-state-feedback.md","lastUpdated":null}'),l={name:"03-interaction-design/notes/00-foundations/04-ia-user-flow-task-flow-state-feedback.md"};function n(r,t,d,o,h,p){return i(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="信息架构、用户流程、任务流程、状态与反馈" tabindex="-1">信息架构、用户流程、任务流程、状态与反馈 <a class="header-anchor" href="#信息架构、用户流程、任务流程、状态与反馈" aria-label="Permalink to &quot;信息架构、用户流程、任务流程、状态与反馈&quot;">​</a></h1><p>信息架构、用户流程、任务流程、状态和反馈处于不同设计层次：信息架构组织内容与功能，流程组织行动与判断，状态描述某一时刻的条件，反馈让状态变化可被用户感知。把它们混成一张页面连线图，会遗漏入口、分支、数据条件和恢复机制。</p><h2 id="概念边界" tabindex="-1">概念边界 <a class="header-anchor" href="#概念边界" aria-label="Permalink to &quot;概念边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>研究对象</th><th>典型产物</th><th>不能替代</th></tr></thead><tbody><tr><td>信息架构（IA）</td><td>内容与功能的分类、命名、层级、导航和检索</td><td>内容模型、分类体系、导航模型、站点地图</td><td>具体任务如何完成</td></tr><tr><td>用户流程</td><td>用户从不同入口达到目标的端到端路径</td><td>含入口、分支、渠道和出口的流程图</td><td>每一步的控件级操作细节</td></tr><tr><td>任务流程</td><td>在给定场景下完成一个有边界任务的操作序列</td><td>步骤、判断、输入、系统响应和完成条件</td><td>整个产品的信息组织</td></tr><tr><td>状态</td><td>系统、对象、页面或控件在某时刻的数据与可操作条件</td><td>状态表、状态机、数据条件</td><td>用户对变化的理解</td></tr><tr><td>反馈</td><td>对动作、进度、结果或错误的可感知响应</td><td>文案、视觉变化、声音、触觉、焦点或状态消息</td><td>真实的数据与业务状态</td></tr></tbody></table><p>站点地图只是 IA 的一种视图；线框图连线只是流程的一种表达；Toast 只是反馈的一种形式。设计完整性取决于各层之间能否追踪，而不是产物数量。</p><h2 id="五层怎样协作" tabindex="-1">五层怎样协作 <a class="header-anchor" href="#五层怎样协作" aria-label="Permalink to &quot;五层怎样协作&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    IA[&quot;信息架构：内容在哪里&quot;] --&gt; UF[&quot;用户流程：从入口到目标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    UF --&gt; TF[&quot;任务流程：具体怎样操作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    TF --&gt; S[&quot;状态：此刻允许什么&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; F[&quot;反馈：用户怎样知道&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; TF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>以“上传文件”为例：IA 决定上传入口属于项目、资料库还是任务；用户流程覆盖通知、项目详情和直接链接等入口；任务流程描述选择文件、校验、上传与确认；状态机区分未选择、上传中、处理中、成功和失败；反馈显示进度、错误原因与恢复操作。</p><h2 id="信息架构" tabindex="-1">信息架构 <a class="header-anchor" href="#信息架构" aria-label="Permalink to &quot;信息架构&quot;">​</a></h2><h3 id="组成部分" tabindex="-1">组成部分 <a class="header-anchor" href="#组成部分" aria-label="Permalink to &quot;组成部分&quot;">​</a></h3><ul><li><strong>内容模型</strong>：有哪些对象、属性和关系，例如项目包含文件，文件具有版本与处理状态。</li><li><strong>组织体系</strong>：按主题、任务、对象、角色、时间或混合维度分类。</li><li><strong>命名体系</strong>：导航、标题、搜索结果和操作使用一致、可区分的语言。</li><li><strong>导航体系</strong>：用户怎样从当前位置到达相关内容。</li><li><strong>搜索与检索</strong>：可搜索字段、筛选、排序、结果呈现和无结果恢复。</li></ul><p>IA 的分类维度应反映用户寻找信息的方式。组织架构和数据库表可以提供约束，但不应自动变成导航结构。</p><h3 id="验证问题" tabindex="-1">验证问题 <a class="header-anchor" href="#验证问题" aria-label="Permalink to &quot;验证问题&quot;">​</a></h3><ul><li>同一对象是否在多个位置重复且状态不一致？</li><li>用户能否从任务语言预测入口名称？</li><li>层级是否稳定，还是经常因权限或组织调整变化？</li><li>搜索结果是否显示足够上下文以区分同名对象？</li></ul><h2 id="用户流程与任务流程" tabindex="-1">用户流程与任务流程 <a class="header-anchor" href="#用户流程与任务流程" aria-label="Permalink to &quot;用户流程与任务流程&quot;">​</a></h2><h3 id="用户流程" tabindex="-1">用户流程 <a class="header-anchor" href="#用户流程" aria-label="Permalink to &quot;用户流程&quot;">​</a></h3><p>用户流程从目标和场景开始，至少包含：</p><ul><li>用户类型与目标；</li><li>站内、外部、通知和恢复入口；</li><li>权限、登录和对象状态等前置条件；</li><li>关键选择、跨渠道步骤和异常出口；</li><li>成功、失败、取消和不符合资格等结束状态。</li></ul><h3 id="任务流程" tabindex="-1">任务流程 <a class="header-anchor" href="#任务流程" aria-label="Permalink to &quot;任务流程&quot;">​</a></h3><p>任务流程把其中一个任务展开到可执行粒度。每个节点使用统一格式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触发条件 → 用户动作 → 系统处理 → 可见反馈 → 结果状态 → 下一步</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果一个节点只有“打开页面”，还不足以实现或测试。应继续说明页面基于什么数据进入哪个状态，用户能执行什么，系统响应后状态怎样变化。</p><h2 id="状态模型" tabindex="-1">状态模型 <a class="header-anchor" href="#状态模型" aria-label="Permalink to &quot;状态模型&quot;">​</a></h2><h3 id="状态层级" tabindex="-1">状态层级 <a class="header-anchor" href="#状态层级" aria-label="Permalink to &quot;状态层级&quot;">​</a></h3><ul><li><strong>系统状态</strong>：在线、维护、认证服务不可用。</li><li><strong>对象状态</strong>：草稿、处理中、已发布、已归档。</li><li><strong>页面或区域状态</strong>：初始、加载、空、成功、失败、无权限、过期。</li><li><strong>控件状态</strong>：默认、悬停、焦点、按下、禁用、只读、忙碌、无效。</li></ul><p>不同层级可以组合。例如页面已加载成功，但某个文件对象仍在服务端处理中；提交按钮处于禁用状态不代表整个页面不可用。</p><h3 id="用条件定义状态" tabindex="-1">用条件定义状态 <a class="header-anchor" href="#用条件定义状态" aria-label="Permalink to &quot;用条件定义状态&quot;">​</a></h3><p>状态名称必须映射到可判断条件：</p><table tabindex="0"><thead><tr><th>状态</th><th>进入条件</th><th>可执行操作</th><th>离开条件</th></tr></thead><tbody><tr><td><code>uploading</code></td><td>文件已通过本地预检并开始传输</td><td>取消</td><td>传输完成、失败或取消</td></tr><tr><td><code>processing</code></td><td>服务端收到完整文件并异步解析</td><td>离开页面、稍后查看</td><td>解析成功或失败</td></tr><tr><td><code>failed-retryable</code></td><td>暂时性网络或服务错误</td><td>重试、替换文件</td><td>重试成功或用户取消</td></tr><tr><td><code>failed-final</code></td><td>文件永久不符合规则</td><td>替换文件</td><td>新文件通过预检</td></tr></tbody></table><p>“错误状态”过于宽泛。是否可重试、数据是否已写入、用户输入是否保留，会决定完全不同的交互。</p><h2 id="反馈模型" tabindex="-1">反馈模型 <a class="header-anchor" href="#反馈模型" aria-label="Permalink to &quot;反馈模型&quot;">​</a></h2><p>反馈回答四个问题：系统是否收到动作、正在做什么、结果是什么、用户下一步能做什么。</p><table tabindex="0"><thead><tr><th>反馈类型</th><th>适用情况</th><th>要求</th></tr></thead><tbody><tr><td>控件内反馈</td><td>点击、选择、输入等即时动作</td><td>靠近动作，不仅依赖颜色</td></tr><tr><td>区域内状态</td><td>列表刷新、模块失败、局部保存</td><td>保留上下文，提供重试或下一步</td></tr><tr><td>状态消息</td><td>不移动焦点的动态结果或进度</td><td>程序可确定，使辅助技术能获知</td></tr><tr><td>焦点转移</td><td>新页面、对话框、必须立即处理的错误</td><td>落点合理，避免无理由中断</td></tr><tr><td>持久结果页</td><td>支付、申请、删除等重要完成结果</td><td>包含对象、结果、时间和后续操作</td></tr></tbody></table><p><code>role=&quot;status&quot;</code> 适合非紧急状态更新；<code>role=&quot;alert&quot;</code> 或 assertive live region 只应用于重要且时间敏感的信息，滥用会持续打断屏幕阅读器用户。状态消息不能只显示图标或颜色。</p><h2 id="完整案例-上传项目数据文件" tabindex="-1">完整案例：上传项目数据文件 <a class="header-anchor" href="#完整案例-上传项目数据文件" aria-label="Permalink to &quot;完整案例：上传项目数据文件&quot;">​</a></h2><h3 id="用户流程-1" tabindex="-1">用户流程 <a class="header-anchor" href="#用户流程-1" aria-label="Permalink to &quot;用户流程&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;项目详情入口&quot;] --&gt; P[&quot;选择文件&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B[&quot;待办通知入口&quot;] --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P --&gt; C{&quot;本地预检通过？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|否| E[&quot;说明格式、大小或缺失问题&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; P</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|是| U[&quot;上传&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U --&gt;|中断| R[&quot;重试或取消&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; U</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U --&gt; Q[&quot;服务端处理&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q --&gt;|成功| S[&quot;结果与下一步&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q --&gt;|部分失败| F[&quot;逐项结果与修正&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="ia-决策" tabindex="-1">IA 决策 <a class="header-anchor" href="#ia-决策" aria-label="Permalink to &quot;IA 决策&quot;">​</a></h3><ul><li>文件属于项目对象，主要入口放在项目详情的“数据文件”区域。</li><li>通知深链携带项目 ID，并在登录后返回同一任务。</li><li>文件详情具有独立 URL，可查看版本、处理结果和错误报告。</li><li>搜索结果显示项目名、文件名、版本和处理状态，避免同名文件混淆。</li></ul><h3 id="任务流程节点" tabindex="-1">任务流程节点 <a class="header-anchor" href="#任务流程节点" aria-label="Permalink to &quot;任务流程节点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>节点</th><th>用户动作</th><th>系统处理</th><th>反馈与状态</th></tr></thead><tbody><tr><td>选择</td><td>选择 CSV 文件</td><td>检查扩展名、大小和基础结构</td><td>显示文件名；失败时给出可修正原因</td></tr><tr><td>上传</td><td>确认上传</td><td>传输文件</td><td>显示可感知进度并允许取消</td></tr><tr><td>处理</td><td>等待或离开</td><td>异步解析数据</td><td>明确“已上传，处理中”，不伪装成最终成功</td></tr><tr><td>完成</td><td>查看结果</td><td>更新文件和项目状态</td><td>显示成功数、失败数、错误下载和下一步</td></tr></tbody></table><h3 id="关键状态与恢复" tabindex="-1">关键状态与恢复 <a class="header-anchor" href="#关键状态与恢复" aria-label="Permalink to &quot;关键状态与恢复&quot;">​</a></h3><ul><li>取消上传：终止传输，清理未完成数据，允许重新选择。</li><li>页面关闭：若服务端已收到文件，重新进入后恢复处理状态。</li><li>部分成功：保留成功记录，列出失败项及是否可只重试失败项。</li><li>重复文件：说明检测依据，允许查看现有版本或确认新版本。</li><li>权限变化：停止进一步写入，保留已经完成的权威结果。</li></ul><h2 id="可执行设计步骤" tabindex="-1">可执行设计步骤 <a class="header-anchor" href="#可执行设计步骤" aria-label="Permalink to &quot;可执行设计步骤&quot;">​</a></h2><ol><li>列出核心对象、属性、关系、术语和用户寻找方式，建立 IA 草图。</li><li>写目标、场景、入口、前置条件和完成标准。</li><li>画端到端用户流程，加入分支、跨渠道、失败、取消和恢复。</li><li>选择一个关键任务，按统一节点格式展开任务流程。</li><li>为每个节点标注系统、对象、页面和控件状态。</li><li>为每次状态变化指定可见反馈、辅助技术通知、持续时间和下一步。</li><li>用真实数据和故障条件运行流程，修正不能映射到数据条件的状态。</li></ol><h2 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h2><ul><li>用站点地图代替完整 IA，遗漏内容模型、命名和检索。</li><li>用户流程从首页开始，忽略通知、搜索和恢复入口。</li><li>流程图只连接页面，没有用户判断、系统处理和状态。</li><li>用“加载”“失败”描述全部状态，却不写进入与离开条件。</li><li>服务器开始处理就显示“完成”，造成阶段性成功与最终成功混淆。</li><li>所有结果都使用短暂 Toast，重要错误消失后无法恢复。</li><li>动态更新只改变颜色或图标，键盘与辅助技术无法获知。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>从每个入口进入任务，确认对象与上下文一致。</li><li>对流程图每条边制造对应条件，检查不存在无法到达或无法退出的状态。</li><li>记录前端展示状态与后端权威状态，验证刷新和重新登录后保持一致。</li><li>仅用键盘完成主路径、失败修正、取消和恢复。</li><li>用屏幕阅读器检查加载、进度、结果和错误能否在不丢失焦点的情况下获知。</li><li>制造断网、超时、部分成功、权限变化和并发更新，验证下一步明确。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“批量邀请项目成员”建立 IA、用户流程、任务流程、状态表和反馈规范。</p><p>完成时应满足：</p><ul><li>IA 说明成员对象、项目关系、入口和术语；</li><li>用户流程至少包含两个入口、权限分支和三个结束状态；</li><li>任务流程每一步包含动作、系统处理、反馈与结果状态；</li><li>状态表覆盖加载、空、部分成功、失败、取消和重复邀请；</li><li>反馈区分非阻断状态消息与需要焦点的上下文变化；</li><li>通过刷新、键盘、屏幕阅读器和故障注入验证。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/tutorials/page-structure/" target="_blank" rel="noreferrer">W3C WAI：Page Structure Tutorial</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/about/introduction/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Introduction</a>（访问日期：2026-07-17）</li><li><a href="https://www.gov.uk/service-manual/design/scoping-your-service" target="_blank" rel="noreferrer">GOV.UK Service Manual：Scoping your service</a>（访问日期：2026-07-17）</li></ul>`,55)])])}const b=a(l,[["render",n]]);export{c as __pageData,b as default};
